mapper.select:
SELECT wr.id, wr.title, wr.report_type, wr.template_id, wr.user_id, wr.report_date, wr.week_number, wr.month_number, wr.content, wr.work_summary, wr.work_plan, wr.issues, wr.status, wr.submit_time, wr.create_time, u.nick_name, d.dept_name AS deptName, rt.template_name FROM tb_work_report wr LEFT JOIN tb_user u ON wr.user_id = u.id AND u.is_deleted = 0 LEFT JOIN tb_department d ON u.department_id = d.id AND d.is_deleted = 0 LEFT JOIN tb_report_template rt ON wr.template_id = rt.id AND rt.is_deleted = 0 WHERE wr.is_deleted = 0
AND wr.title LIKE CONCAT('%', #{dto.title}, '%')
AND wr.report_type = #{dto.reportType}
AND wr.status = #{dto.status}
AND wr.user_id = #{dto.userId}
AND wr.report_date >= #{dto.reportDateBegin}
AND wr.report_date <= #{dto.reportDateEnd}
ORDER BY wr.id DESC

SELECT u.id AS userId, u.nick_name, d.dept_name AS deptName, IFNULL(ds.cnt, 0) AS dailyCount, IFNULL(ws.cnt, 0) AS weeklyCount, IFNULL(ms.cnt, 0) AS monthlyCount, IFNULL(ds.cnt, 0) + IFNULL(ws.cnt, 0) + IFNULL(ms.cnt, 0) AS totalCount FROM tb_user u LEFT JOIN tb_department d ON u.department_id = d.id AND d.is_deleted = 0 LEFT JOIN ( SELECT wr.user_id, COUNT(*) AS cnt FROM tb_work_report wr WHERE wr.is_deleted = 0 AND wr.status = 2 AND wr.report_type = 1
AND wr.report_date >= #{startDate}
AND wr.report_date <= #{endDate}
GROUP BY wr.user_id ) ds ON u.id = ds.user_id LEFT JOIN ( SELECT wr.user_id, COUNT(*) AS cnt FROM tb_work_report wr WHERE wr.is_deleted = 0 AND wr.status = 2 AND wr.report_type = 2
AND wr.report_date >= #{startDate}
AND wr.report_date <= #{endDate}
GROUP BY wr.user_id ) ws ON u.id = ws.user_id LEFT JOIN ( SELECT wr.user_id, COUNT(*) AS cnt FROM tb_work_report wr WHERE wr.is_deleted = 0 AND wr.status = 2 AND wr.report_type = 3
AND wr.report_date >= #{startDate}
AND wr.report_date <= #{endDate}
GROUP BY wr.user_id ) ms ON u.id = ms.user_id WHERE u.is_deleted = 0 AND u.user_status = 1
AND u.department_id = #{deptId}
HAVING totalCount > 0 ORDER BY totalCount DESC
